/// E2E: Read and display markdown file
#[test]
fn test_readme_viewer() {
    let markdown = include_str!("../../README.md");
    let renderer = glamour::Renderer::new(glamour::Style::Dark);
    let rendered = renderer.render(markdown).unwrap();

    let mut viewport = bubbles::viewport::Viewport::new(80, 24);
    viewport.set_content(&rendered);

    // Verify viewport shows content
    let view = viewport.view();
    assert!(view.len() > 0);

    // Test scrolling
    let (viewport, _) = viewport.update(KeyMsg { key_type: KeyType::Down, ..Default::default() });
    assert!(viewport.y_offset() > 0);
}
```

### Scenario 2: Form Submission Flow
```rust
/// E2E: Complete form submission
#[test]
fn test_form_submission_flow() {
    let form = huh::Form::new(vec![
        huh::Group::new(vec![
            huh::Input::new()
                .title("Username")
                .key("username")
                .validate(|s| if s.is_empty() { Err("Required".into()) } else { Ok(()) }),
            huh::Input::new()
                .title("Password")
                .key("password")
                .password(true)
                .validate(|s| if s.len() < 8 { Err("Too short".into()) } else { Ok(()) }),
        ]),
        huh::Group::new(vec![
            huh::Confirm::new()
                .title("Remember me?")
                .key("remember"),
        ]),
    ]);

    // Simulate user input
    let simulation = FormSimulation::new(form)
        .type_text("alice")
        .press(KeyType::Enter)
        .type_text("password123")
        .press(KeyType::Tab)
        .press(KeyType::Enter);

    // Verify values
    assert_eq!(simulation.get("username"), "alice");
    assert_eq!(simulation.get("password"), "password123");
    assert_eq!(simulation.get("remember"), true);
}
```

### Scenario 3: Animated Progress Display
```rust
/// E2E: Progress bar with animation
#[test]
fn test_animated_progress() {
    struct DownloadApp {
        progress: bubbles::progress::Progress,
        spinner: bubbles::spinner::Spinner,
    }

    impl Model for DownloadApp {
        fn init(&self) -> Cmd {
            bubbles::spinner::tick()
        }

        fn update(&self, msg: Msg) -> (Self, Cmd) {
            match msg {
                Msg::Progress(pct) => {
                    (Self { progress: self.progress.set_percent(pct), ..self }, Cmd::none())
                }
                Msg::SpinnerTick => {
                    let (spinner, cmd) = self.spinner.update(msg);
                    (Self { spinner, ..self }, cmd)
                }
                _ => (self, Cmd::none())
            }
        }

        fn view(&self) -> String {
            if self.progress.percent() < 1.0 {
                format!("{} Downloading... {}", self.spinner.view(), self.progress.view())
            } else {
                "✓ Complete!".to_string()
            }
        }
    }

    let app = DownloadApp::new();

    // Simulate download progress
    let (app, _) = app.update(Msg::Progress(0.25));
    assert!(app.view().contains("Downloading"));

    let (app, _) = app.update(Msg::Progress(1.0));
    assert!(app.view().contains("Complete"));
}
```

